// Last 7 days window for weekly report
const now = new Date();
const from = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
return items.map(i => ({
  json: {
    ...i.json,
    from_iso: from.toISOString(),
    to_iso: now.toISOString(),
  }
}));

// Build CSV and aggregate totals
const rows = $json;
const header = ['booking_id','created_at','module','status','employee','department','listing','vendor','total_amount'];
const cells = (v) => `"${String(v ?? '').replace(/"/g,'""')}"`;
const lines = rows.map(r => [
  r.id,
  r.created_at,
  r.module,
  r.status,
  r.user_profiles?.full_name ?? '',
  r.user_profiles?.department ?? '',
  r.listings?.title ?? '',
  r.vendors?.business_name ?? '',
  r.total_amount ?? 0,
].map(cells).join(','));
const csv = [header.join(','), ...lines].join('\n');
const total = rows.reduce((s,r) => s + (Number(r.total_amount)||0), 0);
return [{ json: { csv, total, count: rows.length, corporate_id: $node['Compute Window'].json.id, corporate_name: $node['Compute Window'].json.name, from_iso: $node['Compute Window'].json.from_iso, to_iso: $node['Compute Window'].json.to_iso, account_manager_id: $node['Compute Window'].json.account_manager_id } }];
